        // update enumerable sets
        if (oldRoleId != ADMIN_ROLE) {
            _roleTargetFunctions[oldRoleId][target].remove(selector);
        }
        if (roleId != ADMIN_ROLE) {
            _roleTargetFunctions[roleId][target].add(selector);
        }
