        // Calculate expected bounds after sanitization
        uint256 sanitizedEnd = Math.min(end, values.length);
        uint256 sanitizedStart = Math.min(start, sanitizedEnd);
        uint256 expectedLength = sanitizedEnd - sanitizedStart;
